// CS Errores — registra una ejecución fallida en staticData (últimas 100).
const e = $input.first().json || {};
const exec = e.execution || {};
const wf = e.workflow || {};
const err = exec.error || {};

const entry = {
  ts: new Date().toISOString(),
  workflow_id: wf.id || null,
  workflow_name: wf.name || null,
  execution_id: exec.id || null,
  execution_url: exec.url || null,
  node: exec.lastNodeExecuted || null,
  mode: exec.mode || null,
  error_name: err.name || null,
  message: err.message || 'sin mensaje'
};

const sd = $getWorkflowStaticData('global');
if (!Array.isArray(sd.errors)) sd.errors = [];
sd.errors.unshift(entry);                 // más reciente primero
if (sd.errors.length > 100) sd.errors.length = 100;

return [{ json: entry }];

// CS Errores — sirve el log de errores; ?clear=1 lo purga.
const items = $input.all();
const q = (items[0] && items[0].json && items[0].json.query) || {};
const sd = $getWorkflowStaticData('global');
if (q.clear === '1' || q.clear === 'true') sd.errors = [];
const errors = Array.isArray(sd.errors) ? sd.errors : [];
return [{ json: {
  generated_at: new Date().toISOString(),
  source: 'n8n-webhook-cs-errors',
  count: errors.length,
  last_error_ts: errors.length ? errors[0].ts : null,
  errors: errors
} }];

